mapper.select:
SELECT so.so_id, so.so_no, so.customer_id, DATE_FORMAT(so.order_date, '%Y-%m-%d') AS order_date, DATE_FORMAT(so.delivery_date, '%Y-%m-%d') AS delivery_date, so.status, so.created_by, DATE_FORMAT(so.created_at, '%Y-%m-%d %H:%i') AS created_at, c.customer_name, m.name AS created_by_name FROM SALES_ORDER so INNER JOIN CUSTOMER c ON so.customer_id = c.customer_id INNER JOIN member m ON so.created_by = m.member_id
AND (so.so_no LIKE CONCAT('%', #{keyword}, '%') OR c.customer_name LIKE CONCAT('%', #{keyword}, '%'))
AND so.status = #{status}
AND so.order_date >= #{fromDate}
AND so.order_date <= #{toDate}
ORDER BY so.so_id DESC

mapper.update:
UPDATE SALES_ORDER
SET    customer_id   = #{customerId},
       order_date    = #{orderDate},
       delivery_date = #{deliveryDate}
WHERE  so_id = #{soId}

UPDATE SALES_ORDER
SET    status = #{status}
WHERE  so_id = #{soId}
